import './StepperMobileStep.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import { Typography } from '../../Typography';
import { ICON_STATE_MAP, ORDER_STATE_MAP, STEP_ICON_MAP } from '../common/constants';
import type { MobileStepProps } from './StepperMobileStep.types';

export const StepperMobileStep: FC<MobileStepProps> = ({
	id,
	state = 'non-visited',
	activated = false,
	order,
	onClick,
}) => {
	const handleClick = (): void => {
		onClick?.(id);
	};

	return (
		<div
			className={classNames(
				'dsb_mobile-step',
				`dsb_mobile-step__${state}`,
				state !== 'disabled' && onClick && 'dsb_mobile-step__clickable',
			)}
			onClick={handleClick}
			onKeyDown={event => event.key === 'Enter' && handleClick()}
			role={state !== 'disabled' && onClick ? 'button' : 'presentation'}
			tabIndex={state !== 'disabled' && onClick ? 0 : -1}
		>
			<div
				className={classNames(
					'dsb_mobile-step-border',
					'dsb_mobile-step-border__direction-horizontal',
					activated && 'dsb_mobile-step-border__active',
				)}
			/>
			{ORDER_STATE_MAP[state] && (
				<div className={classNames('dsb_mobile-step-order', `dsb_mobile-step-order__${state}`)}>
					<Typography className="dsb_mobile-step-order-number" variant="body2">
						{order}
					</Typography>
				</div>
			)}

			{ICON_STATE_MAP[state] && (
				<Icon
					className={classNames('dsb_mobile-step-icon', `dsb_mobile-step-icon__${state}`)}
					iconName={STEP_ICON_MAP[state]}
					size="large"
				/>
			)}
		</div>
	);
};
